1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  cursed?: boolean;
8	}
9	
10	export interface Damage {
11	  itemType: string;
12	  amount: number;
13	}
14	
15	export interface Incident {
16	  cause: string;
17	  damages: Damage[];
18	}
19	
20	export interface Policy {
21	  items: Item[];
22	  insuranceSum: number;
23	  cap: number;
24	  remainingCap: number;
25	}
