27	const PROCESSING_FEE = 5;
28	const FIRST_INSURANCE_RATE = 0.1;
29	
30	const BASE_PREMIUM: Record<string, number> = {
31	  sword: 100,
32	  amulet: 60,
33	  staff: 80,
34	  potion: 40,
35	  rune: 25,
36	  moonstone: 25,
37	};
38	
39	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
40	const BLOCK_BASE = 60;
41	
42	const baseForGroup = (type: string, count: number): number => {
43	  if (COMPONENT_TYPES.has(type) && count === 3) return BLOCK_BASE;
44	  return BASE_PREMIUM[type] * count;
45	};
46	
47	const countByType = (items: Item[]): Map<string, number> => {
48	  const counts = new Map<string, number>();
49	  for (const item of items) {
50	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
51	  }
52	  return counts;
53	};
54	
55	const withFirstInsurance = (base: number): number =>
56	  base + base * FIRST_INSURANCE_RATE;
57	
58	const itemSurcharges = (item: Item, base: number): number => {
59	  let surcharges = 0;
60	  if (item.cursed) surcharges += base * 0.5;
61	  return surcharges;
62	};
63	
64	export const quote = (
65	  _customer: Customer,
66	  items: Item[],
67	  _priorContracts: number,
68	): number => {
69	  let itemsTotal = 0;
70	  const counts = countByType(items);
71	  for (const [type, count] of counts) {
72	    const groupBase = baseForGroup(type, count);
73	    itemsTotal += withFirstInsurance(groupBase);
74	  }
75	  for (const item of items) {
76	    const base = BASE_PREMIUM[item.type];
77	    itemsTotal += itemSurcharges(item, base);
78	  }
79	  return Math.ceil(itemsTotal + PROCESSING_FEE);
80	};
81	
82	export const claim = (
83	  _policy: Policy,
84	  _incident: Incident,
85	): { payout: number; remainingCap: number } => {
86	  return undefined as unknown as { payout: number; remainingCap: number };
87	};
88

