82	  // Standard reimbursement (no special clauses)
83	  it.todo("regular steel sword ench 3, damage 500 → payout 400 (500 − 100 deductible)");
84	  it.todo("rune (no enchantment / material), damage 200 → payout 100 (200 − 100 deductible)");
85	
86	  // Enchantment ≥8 clause
87	  it.todo("steel sword ench 9, damage 1000 → payout 400 (50% then deductible)");
88	
89	  // Dragon material clause
90	  it.todo("dragon-material sword ench 5, damage 800 → payout 700 (full, then deductible)");
91	
92	  // Both clauses — 50% wins, then deductible
93	  it.todo("dragon-material sword ench 9, damage 1000 → payout 400");
94	  it.todo("dragon-material sword ench exactly 8, damage 1000 → payout 400 (high-ench applies, then deductible)");
95	
96	  // Deductible per damage event
97	  it.todo("dragon attack damaging sword 500 + amulet 300 → payout 600 (deductible per item)");
98	
99	  // Multiple items of same type
100	  it.todo("policy with two swords; damage to both → each treated as separate damage with own deductible");
101	  it.todo("damages array has more entries of a type than the policy covers → throws error");
102	
103	  // Cap exhaustion
104	  it.todo("policy: sword + amulet → insurance sum 1600, cap 3200");
105	  it.todo("policy: cursed sword → cap 2000 (based on unmodified insurance value)");
106	  it.todo("policy: sword + 3 runes (block) → insurance sum 1750 (block doesn't affect sum)");
107	  it.todo("sword (cap 2000), first claim 1500 → payout 1400, remaining 600; second claim 1500 → payout 600, remaining 0");
108	
109	  // Rounding for payouts
110	  it.todo("payout calculation yielding 350.5 → final payout 350 (rounded down)");
111	
112	  // Errors
113	  it.todo("claim references damage for an item not in the policy → throws error");
114	  it.todo("claim contains damage with negative amount → throws error");
115	});
