const withFirstInsurance = (base: number): number =>
  base + base * FIRST_INSURANCE_RATE;

const itemSurcharges = (item: Item, base: number): number => {
  let surcharges = 0;
  if (item.cursed) surcharges += base * 0.5;
  return surcharges;
};

export const quote = (
  _customer: Customer,
  items: Item[],
  _priorContracts: number,
): number => {
  let itemsTotal = 0;
  const counts = countByType(items);
  for (const [type, count] of counts) {
    const groupBase = baseForGroup(type, count);
    itemsTotal += withFirstInsurance(groupBase);
  }
  for (const item of items) {
    const base = BASE_PREMIUM[item.type];
    itemsTotal += itemSurcharges(item, base);
  }
  return Math.ceil(itemsTotal + PROCESSING_FEE);
};

